def debate_termination_filter(message, sender, recipient):
    convo_turns = getattr(debate_termination_filter, 'turns', 0)
    debate_termination_filter.turns += 1

    if debate_termination_filter.turns > 20:
        return "[TERMINATED] Debate limit reached. Attorney review required."

    result = vex.check(message, policy="legal-debate")
    if not result.approved or 'unresolved' in message.lower():
        return "[BLOCKED] No consensus or invalid conclusion. Escalate to attorney."
    return message

